17	#### --- Key Reads ---
18	
19	```dataviewjs
20	const cutoff = dv.date("today").minus({ days: 30 });
21	
22	const pages = dv.pages('"Brainfood/Articles"')
23	    .where(p => p.date && dv.date(p.date) >= cutoff)
24	    .sort(p => dv.date(p.date), 'desc');
25	
26	for (let page of pages) {
27	    dv.paragraph(`- **${page.title || page.file.name}**
28	  - ${page.keyinsights || "No insights captured"}  
29	  - → Takeaway: ${page.whyitmatters || "No takeaway captured"}
30	  - **Read more**: [Link](${page.url || "#"})`);
31	}
32	
33	if (pages.length === 0) {
34	    dv.paragraph("*No articles captured this week*");
35	}
36	```
